Write-Host "Actualizando MICSA REPSE..." -ForegroundColor Cyan
$b64 = ""
$b64 += ""
$b64 += ""
$b64 += ""
$b64 += ""
$b64 += ""
$bytes = [System.Convert]::FromBase64String($b64)
$text = [System.Text.Encoding]::UTF8.GetString($bytes)

# Escribir App.jsx
[System.IO.File]::WriteAllText("$PWD\src\App.jsx", $text, [System.Text.Encoding]::UTF8)
Write-Host "App.jsx escrito: $(([System.IO.FileInfo]"$PWD\src\App.jsx").Length) bytes" -ForegroundColor Green

# Verificar primeras 2 lineas
$preview = Get-Content src\App.jsx -TotalCount 2
Write-Host "Verificacion: $preview" -ForegroundColor Cyan

# Force timestamp
$ts = Get-Date -Format "yyyy-MM-dd HH:mm:ss"
Set-Content -Path "build.txt" -Value "rebuild $ts"

# Git push forzado
git add -A
git status
git commit -m "fix documentos generador $ts"
git push

Write-Host "LISTO - Vercel desplegara en 60 segundos" -ForegroundColor Green
Write-Host "https://micsa-repse.vercel.app" -ForegroundColor Yellow